import{_ as t,c as r,o as i,ag as o}from"./chunks/framework.Dj4VfQLU.js";const u=JSON.parse('{"title":"Architecture Overview","description":"","frontmatter":{"icon":"sitemap"},"headers":[],"relativePath":"architecture-overview.md","filePath":"architecture-overview.md"}'),a={name:"architecture-overview.md"};function s(n,e,c,l,d,g){return i(),r("div",null,e[0]||(e[0]=[o('<h1 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h1><h4 id="🧩-architecture-overview" tabindex="-1">🧩 Architecture Overview <a class="header-anchor" href="#🧩-architecture-overview" aria-label="Permalink to &quot;🧩 Architecture Overview&quot;">​</a></h4><p>BetterTaxi follows a <strong>microservice-based</strong>, <strong>API-first architecture</strong> designed for scalability, modularity, and ease of integration into broader ecosystems like <strong>BetterSuite</strong>.</p><p><strong>🔁 Core Architecture</strong></p><ul><li><strong>API Layer:</strong> GraphQL (type-safe, developer-friendly, used across all clients)</li><li><strong>Backend Stack:</strong> Node.js microservices (e.g., user service, trip service, payment processor)</li><li><strong>Frontend Clients:</strong> Flutter apps (Driver &amp; Customer), web-based Admin Panel</li><li><strong>Authentication:</strong> JWT-based user authentication</li><li><strong>WebSocket Support:</strong> Real-time updates via GraphQL subscriptions (<code>graphql-ws</code>)</li></ul><p><strong>🗺️ Third-Party Integrations</strong></p><ul><li><strong>Maps:</strong> 5 options available through the in-house <code>generic_map</code> Flutter library</li><li><strong>Payments:</strong> 22 payment gateways integrated into the standalone <strong>Payment Processor</strong> microservice</li><li><strong>Messaging:</strong> 8 SMS providers integrated into the backend (selectable via config)</li></ul><hr><p>This architecture ensures BetterTaxi can be scaled horizontally, integrated with external tools or services, and extended with future add-ons such as <strong>Partnership Models</strong> or integrations with <strong>BetterShop</strong>.</p>',9)]))}const p=t(a,[["render",s]]);export{u as __pageData,p as default};
